class Solution {
public:
    int racecar(int target) {
        vector<int> dp(target + 3, INT_MAX);
        queue<int> q;
        q.push(0);
        dp[0] = 0;
        while (!q.empty()) {
            int pos = q.front(); q.pop();
            if (pos == target) return dp[pos];
            int step = dp[pos] + 1;
            int nextPos = pos + (1 << dp[pos]);
            if (abs(nextPos - target) < target + 2 && (dp[abs(nextPos)] == INT_MAX || step < dp[abs(nextPos)])) {
                dp[abs(nextPos)] = step;
                q.push(abs(nextPos));
            }
            nextPos = pos;
            step = dp[pos] + 2;
            if (abs(nextPos - target) < target + 2 && (dp[abs(nextPos)] == INT_MAX || step < dp[abs(nextPos)])) {
                dp[abs(nextPos)] = step;
                q.push(abs(nextPos));
            }
        }
        return dp[target];
    }
};
```
efficiency: HIGH
time complexity: O(target log target)
space complexity: O(target)
energy implications: LOW
explanation: Uses BFS with pruning to explore states (position, speed) while memoizing minimal steps. Each state branches into accelerate or reverse, but pruning keeps the search space near target.

